module	tlu_addern_32 (din, incr, sum);
parameter ADDER_DATA_WIDTH = 33;
parameter INCR_DATA_WIDTH  =  1;
parameter UPPER_DATA_WIDTH =  ADDER_DATA_WIDTH - INCR_DATA_WIDTH;
input	[ADDER_DATA_WIDTH-1:0]	din;
input	[INCR_DATA_WIDTH-1:0]   incr;
output	[ADDER_DATA_WIDTH-1:0]	sum;
  wire _n01 = din[ADDER_DATA_WIDTH-1:0][0] ^ {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[0];
  wire _c01 = din[ADDER_DATA_WIDTH-1:0][0] & {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[0];
  wire _n02 = din[ADDER_DATA_WIDTH-1:0][1] ^ {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[1] ^ _c01;
  wire _c02 = (din[ADDER_DATA_WIDTH-1:0][1] & {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[1]) | (din[ADDER_DATA_WIDTH-1:0][1] & _c01) | ({{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[1] & _c01);
  wire _n03 = din[ADDER_DATA_WIDTH-1:0][2] ^ {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[2] ^ _c02;
  wire _c03 = (din[ADDER_DATA_WIDTH-1:0][2] & {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[2]) | (din[ADDER_DATA_WIDTH-1:0][2] & _c02) | ({{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[2] & _c02);
  wire _n04 = din[ADDER_DATA_WIDTH-1:0][3] ^ {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[3] ^ _c03;
  wire _c04 = (din[ADDER_DATA_WIDTH-1:0][3] & {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[3]) | (din[ADDER_DATA_WIDTH-1:0][3] & _c03) | ({{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};
endmodule
